function englishVersionDiffCommentary(msgType) {
  const latestInfo = ISO_LATEST_BY_SLUG[msgType.slug];
  if (!latestInfo) return "";

  const isCurrent = latestInfo.latest === msgType.slug;
  return `
## Version commentary

ISO 20022 last updated this business area on ${latestInfo.date}. This site documents \`${msgType.slug}\`${isCurrent ? `, which still matches the latest catalogue version.` : `. The latest catalogue version is \`${latestInfo.latest}\`.`}

${isCurrent
    ? `Use this page for current implementation work, but still check scheme guidance before production use.`
    : `Use this page for the version that pacs008 implements today, and review the newer catalogue version for roadmap planning.`}
`;
}

function englishSchemeNotes(msgType) {
  const bySlug = {
    "pacs.002.001.12": [
      `In SEPA credit-transfer and instant-payment flows, pacs.002 is the main companion status message. See the [EPC SCT rulebook](${PRIMARY_SOURCES.epcSct}) and [EPC SCT Inst rulebook](${PRIMARY_SOURCES.epcSctInst}).`,
      `In CBPR+, pacs.002 sits alongside pacs.008, pacs.009, and pacs.004 in the Swift rollout. See [Swift's CBPR+ ISO 20022 usage-guidelines announcement](${PRIMARY_SOURCES.swiftGuidelines}).`
    ],
    "pacs.003.001.09": [
      `This message is outside the SCT and SCT Inst credit-transfer rulebooks, so treat it as a separate direct-debit track.`,
      `Use this page as a guide, not as a substitute for scheme rulebooks.`
    ],
    "pacs.004.001.11": [
      `For SEPA credit-transfer flows, pacs.004 sits in the wider return and exception path defined by the [EPC SCT rulebook](${PRIMARY_SOURCES.epcSct}) and [EPC SCT Inst rulebook](${PRIMARY_SOURCES.epcSctInst}).`,
      `In CBPR+, Swift maps pacs.004 alongside pacs.008, pacs.009, and pacs.002. See the [CBPR+ roadmap](${PRIMARY_SOURCES.swiftRoadmap}).`
    ],
    "pacs.007.001.11": [
      `pacs.007 is closer to recall and reversal handling than to beneficiary-side returns, so do not collapse it into the same process model as pacs.004.`,
      `It is often used for fast exception handling in instant-payment and fraud-response contexts.`
    ],
    "pacs.008.001.13": [
      `For SEPA credit transfers, pacs.008 is part of the SCT stack in the [EPC SCT rulebook](${PRIMARY_SOURCES.epcSct}).`,
      `For instant payments, pacs.008 is also central to SCT Inst in the [EPC SCT Inst rulebook](${PRIMARY_SOURCES.epcSctInst}).`,
      `For CBPR+, pacs.008 replaces MT103-style customer payment instructions. See [Swift CBPR+ pacs.008 overview](${PRIMARY_SOURCES.swiftCbprPacs008}), [serial method](${PRIMARY_SOURCES.swiftCbprSerial}), and [cover method](${PRIMARY_SOURCES.swiftCbprCover}).`,
      `The November 2026 structured-address change affects cross-border pacs.008 data quality. See the [Swift CBPR+ roadmap](${PRIMARY_SOURCES.swiftAddress}).`
    ],
    "pacs.009.001.10": [
      `In CBPR+, pacs.009 carries bank-to-bank credit transfers and cover-payment legs. See the [roadmap PDF](${PRIMARY_SOURCES.swiftRoadmap}) and [CBPR+ pacs.009 material](${PRIMARY_SOURCES.swiftCbprPacs009}).`,
      `For cover method, read pacs.009 with the related customer leg in pacs.008. See [Swift's pacs.008/pacs.009 cover-method page](${PRIMARY_SOURCES.swiftCbprCover}).`,
      `This message is outside the SCT and SCT Inst customer credit-transfer rulebooks, so SEPA customer-payment rules do not carry over unchanged.`
    ],
    "pacs.010.001.05": [
      `pacs.010 is not part of the SCT or SCT Inst credit-transfer rulebooks, so credit-transfer rules do not carry over here.`,
      `Use this page as a guide for bank-to-bank direct-debit scenarios, not as a substitute for market-scheme documentation.`
    ],
    "pacs.028.001.05": [
      `pacs.028 is the active status-request partner to pacs.002. Use it when a team must ask for status instead of waiting for an update.`,
      `It works best when the scheme, counterparty agreement, or internal operations model defines clear timing and escalation rules.`
    ]
  };

  const notes = bySlug[msgType.slug] ?? [];
  if (notes.length === 0) return "";

  return `
## Scheme-specific notes

${notes.map((item) => `- ${item}`).join("\n")}
`;
}

function englishFaq(msgType) {
  const faqBySlug = {
    "pacs.002.001.12": [
      ["Is pacs.002 a payment message?", "No. It reports status for an earlier instruction rather than moving value itself."],
      ["Should pacs.002 replace internal workflow states?", "No. It should inform them, but internal case states still need their own operational logic."]
    ],
    "pacs.003.001.09": [
      ["Is pacs.003 the direct-debit mirror of pacs.008?", "No. It handles customer direct-debit flows, which have different mandate, timing, and exception rules."],
      ["What matters most operationally?", "Mandate quality, debtor-account rules, and return handling matter more than XML generation."]
    ],
    "pacs.004.001.11": [
      ["What is the difference between pacs.004 and pacs.007?", "pacs.004 returns settled funds from the receiving side, while pacs.007 requests reversal from the original instructing side."],
      ["Should every failed beneficiary credit become pacs.004?", "Not automatically. The right path depends on scheme rules, settlement stage, and counterparty handling."]
    ],
    "pacs.007.001.11": [
      ["Is pacs.007 only for fraud scenarios?", "No. Fraud is a major use case, but any instructing-side need to reverse a payment can trigger it."],
      ["Can it be handled like a normal return?", "No. Reversal timing, reason capture, and reconciliation differ materially from returns."]
    ],
    "pacs.008.001.13": [
      ["Is pacs.008 enough on its own for production payments?", "No. Production readiness also depends on scheme rules, address quality, party data, status handling, and exception flows."],
      ["What causes the most repair work?", "Weak party data, poor address structuring, inconsistent identifiers, and unstructured remittance content are common causes."]
    ],
    "pacs.009.001.10": [
      ["When should I choose pacs.009 over pacs.008?", "Choose pacs.009 for own-account transfers and cover legs; choose pacs.008 for customer-credit-transfer instructions."],
      ["Why is pacs.009 often harder to reconcile than expected?", "Because banks must preserve the relationship between treasury funding, correspondent legs, and any linked customer payment."]
    ],
    "pacs.010.001.05": [
      ["Is pacs.010 common in retail payment products?", "Usually no. It fits bank-to-bank direct-debit scenarios better than standard retail products."],
      ["What should teams design first?", "Start with approval rules, bilateral controls, and exception handling before finalising XML templates."]
    ],
    "pacs.028.001.05": [
      ["Should pacs.028 be sent after every payment?", "Usually no. It works best as a targeted exception tool, not as blanket traffic."],
      ["What makes pacs.028 useful?", "Clear timeout, escalation, and reconciliation rules around the original payment case."]
    ]
  };

  const items = faqBySlug[msgType.slug];
  if (!items) return "";

  return `
## Implementation FAQ

${items.map(([q, a]) => `### ${q}\n\n${a}`).join("\n\n")}
`;
}

