function englishDecisionFlow(msgType) {
  const flows = {
    "pacs.002.001.12": [
      "Need to communicate status of an earlier instruction?",
      "Yes -> Use pacs.002.",
      "No -> Need to ask another institution for status?",
      "Yes -> Consider pacs.028 instead.",
      "No -> Stay in the payment or exception flow."
    ],
    "pacs.003.001.09": [
      "Need a bank-to-bank customer direct debit?",
      "Yes -> Use pacs.003.",
      "No -> Need a customer credit transfer?",
      "Yes -> Use pacs.008 instead.",
      "No -> Re-check whether the case is really a direct debit."
    ],
    "pacs.004.001.11": [
      "Has value already settled and now needs to move back?",
      "Yes -> Use pacs.004.",
      "No -> Is the instructing side trying to stop or reverse the payment?",
      "Yes -> Consider pacs.007 instead.",
      "No -> Review scheme exception handling before you choose a message."
    ],
    "pacs.007.001.11": [
      "Is the instructing side requesting reversal of an earlier instruction?",
      "Yes -> Use pacs.007.",
      "No -> Has the receiving side already returned settled funds?",
      "Yes -> Consider pacs.004 instead.",
      "No -> Check whether the case is status, investigation, or recall handling."
    ],
    "pacs.008.001.13": [
      "Is this a customer credit-transfer instruction between banks?",
      "Yes -> Use pacs.008.",
      "No -> Is it an institution funding leg or cover payment?",
      "Yes -> Consider pacs.009 instead.",
      "No -> Re-check whether the case is status, return, or reversal."
    ],
    "pacs.009.001.10": [
      "Is this own-account bank movement or a cover leg?",
      "Yes -> Use pacs.009.",
      "No -> Is it a customer payment instruction?",
      "Yes -> Consider pacs.008 instead.",
      "No -> Check whether treasury or settlement operations own the case."
    ],
    "pacs.010.001.05": [
      "Need a bank-to-bank direct-debit message?",
      "Yes -> Use pacs.010.",
      "No -> Need a customer direct-debit flow?",
      "Yes -> Consider pacs.003 instead.",
      "No -> Re-check whether the case is really a credit transfer."
    ],
    "pacs.028.001.05": [
      "Need to ask for status because unsolicited updates are not enough?",
      "Yes -> Use pacs.028.",
      "No -> Need to send status instead of request it?",
      "Yes -> Consider pacs.002 instead.",
      "No -> Keep the case in normal operational monitoring."
    ]
  };

  const steps = flows[msgType.slug];
  if (!steps) return "";

  return `
## Decision flow

\`\`\`text
${steps.join("\n")}
\`\`\`
`;
}

function localizedSelectionGuide(localeKey) {
  const copy = seoCopy(localeKey);
  const t = copyFor(localeKey);
  const reviewLine = sourceReviewLine(localeKey);
  const englishExtra = localeKey === "en"
    ? `
## How to choose fast

- Start with the business event.
- Check who owns the payment at that stage.
- Check whether value is moving, being reported, being returned, or being queried.
- Confirm the scheme and counterparty rules before freeze the template.

## 2026 implementation signals

- Structured address quality is moving from best practice to release gate.
- Banks want less manual repair, so status design and field quality matter as much as XML generation.
- Multi-rail teams need one clear map across customer, treasury, and exception flows.
`
    : "";
  const quickDecisionTable = htmlTable({
    className: "decision-matrix-table",
    ariaLabel: copy.quickDecisionMatrix,
    columns: [
      { className: "decision-matrix-table__col-id", label: t.msgTypeColId },
      { className: "decision-matrix-table__col-name", label: t.msgTypeColDesc },
      { className: "decision-matrix-table__col-overview", label: t.msgDetailOverview }
    ],
    rows: messageTypes.map((msgType) => [
      {
        className: "decision-matrix-table__id",
        html: `<a href="${escapeHtml(localePath(localeKey, msgType.slug))}"><code>${escapeHtml(msgType.slug)}</code></a>`
      },
      {
        className: "decision-matrix-table__name",
        html: escapeHtml(localizedMessageName(localeKey, msgType))
      },
      {
        className: "decision-matrix-table__overview",
        html: escapeHtml(t[msgType.copyPrefix + "Overview"])
      }
    ])
  });
  const comparisonTable = htmlTable({
    className: "comparison-points-table",
    ariaLabel: copy.commonComparisonPoints,
    columns: [
      { className: "comparison-points-table__col-compare", label: copy.compare },
      { className: "comparison-points-table__col-key", label: copy.keyDistinction }
    ],
    rows: [
      [
        { className: "comparison-points-table__compare", html: "<code>pacs.008</code> vs <code>pacs.009</code>" },
        { className: "comparison-points-table__key", html: escapeHtml(copy.customerVsInstitution) }
      ],
      [
        { className: "comparison-points-table__compare", html: "<code>pacs.004</code> vs <code>pacs.007</code>" },
        { className: "comparison-points-table__key", html: escapeHtml(copy.returnVsReversal) }
      ],
      [
        { className: "comparison-points-table__compare", html: "<code>pacs.002</code> vs <code>pacs.028</code>" },
        { className: "comparison-points-table__key", html: escapeHtml(copy.statusVsRequest) }
      ]
    ]
  });

  const introText = normalizeWhitespace(copy.selectionGuideIntro);
  const intro = reviewLine
    ? `${introText}\n\n${reviewLine}`
    : introText;

  return `# ${copy.selectionGuideTitle}

${intro}

## ${copy.quickDecisionMatrix}

${quickDecisionTable}

## ${copy.commonComparisonPoints}

${comparisonTable}

## ${copy.supportedMessagePages}

${localeKey === "en"
    ? `Supported message pages are listed in [Message Types](/message-types/).`
    : messageCoverageList(localeKey)}
${englishExtra}
`;
}

